            message=(
                "This vLLM engine does not support `store=True` and "
                "therefore does not support the background mode. To "
                "enable these features, set the environment variable "
                "`VLLM_ENABLE_RESPONSES_API_STORE=1` when launching "
                "the vLLM server."),
